  1→import { useTranslation } from "@/platform/i18n/useTranslation";
  2→import { type JSX, useEffect, useMemo, useRef, useState } from "react";
  3→import {
  4→  ActivityIndicator,
  5→  Animated,
  6→  StyleSheet,
  7→  useWindowDimensions,
  8→  View,
  9→} from "react-native";
 10→import Svg, { Defs, Ellipse, RadialGradient, Stop } from "react-native-svg";
 11→
 12→const ROTATING_KEYS = [
 13→  "m1",
 14→  "m2",
 15→  "m3",
 16→  "m4",
 17→  "m5",
 18→  "m6",
 19→  "m7",
 20→  "m8",
 21→  "m9",
 22→  "m10",
 23→] as const;
 24→
 25→const INTERVAL_MS = 3000;
 26→const FADE_DURATION_MS = 500;
 27→
 28→const ELLIPSE_WIDTH_RATIO = 0.8;
 29→const ELLIPSE_HEIGHT = 300;
 30→
 31→function VignetteOverlay(): JSX.Element {
 32→  const { width, height } = useWindowDimensions();
 33→  const cx = width / 2;
 34→  const cy = height / 2;
 35→  const rx = (width * ELLIPSE_WIDTH_RATIO) / 2;
 36→  const ry = ELLIPSE_HEIGHT / 2;
 37→
 38→  return (
 39→    <Svg style={StyleSheet.absoluteFill}>
 40→      <Defs>
 41→        <RadialGradient id="vignette" cx="50%" cy="50%" rx="50%" ry="50%">
 42→          <Stop offset="0" stopColor="black" stopOpacity="0.7" />
 43→          <Stop offset="1" stopColor="black" stopOpacity="0" />
 44→        </RadialGradient>
 45→      </Defs>
 46→      <Ellipse cx={cx} cy={cy} rx={rx} ry={ry} fill="url(#vignette)" />
 47→    </Svg>
 48→  );
 49→}
 50→
 51→function shuffle<T>(array: Array<T>): Array<T> {
 52→  const result = [...array];
 53→  for (let i = result.length - 1; i > 0; i--) {
 54→    const j = Math.floor(Math.random() * (i + 1));
 55→    [result[i], result[j]] = [result[j], result[i]];
 56→  }
 57→  return result;
 58→}
 59→
 60→export function ProcessingIndicator(): JSX.Element {
 61→  const { t } = useTranslation();
 62→  const shuffled = useMemo(() => shuffle([...ROTATING_KEYS]), []);
 63→  const [index, setIndex] = useState(-1); // -1 = first message
 64→  const opacity = useRef(new Animated.Value(1)).current;
 65→
 66→  useEffect(() => {
 67→    const interval = setInterval(() => {
 68→      Animated.timing(opacity, {
 69→        toValue: 0,
 70→        duration: FADE_DURATION_MS,
 71→        useNativeDriver: true,
 72→      }).start(() => {
 73→        setIndex((prev) => {
 74→          const next = prev + 1;
 75→          return next >= shuffled.length ? 0 : next;
 76→        });
 77→        Animated.timing(opacity, {
 78→          toValue: 1,
 79→          duration: FADE_DURATION_MS,
 80→          useNativeDriver: true,
 81→        }).start();
 82→      });
 83→    }, INTERVAL_MS);
 84→
 85→    return () => clearInterval(interval);
 86→  }, [opacity, shuffled.length]);
 87→
 88→  const key = index < 0 ? "first" : shuffled[index];
 89→  const message = t(`processing.messages.${key}`);
 90→
 91→  return (
 92→    <View style={styles.container}>
 93→      <VignetteOverlay />
 94→      <ActivityIndicator size="large" color="white" />
 95→      <Animated.Text style={[styles.text, { opacity }]}>{message}</Animated.Text>
 96→    </View>
 97→  );
 98→}
 99→
100→const styles = StyleSheet.create({
101→  container: {
102→    position: "absolute",
103→    top: 0,
104→    left: 0,
105→    right: 0,
106→    bottom: 0,
107→    justifyContent: "center",
108→    alignItems: "center",
109→    gap: 16,
110→  },
111→  text: {
