 27→export function RecipeViewScreen({ id }: { id: RecipeId }): JSX.Element | null {
 28→  const recipe = useRecipeById(id);
 29→  const router = useRouter();
 30→  const { t } = useTranslation();
 31→  const { setDebugData } = useDebugContext();
 32→  const { deleteRecipe } = useRecipes();
 33→
 34→  useEffect(() => {
 35→    return () => {
 36→      setDebugData(null);
 37→    };
 38→  }, [setDebugData]);
 39→
 40→  const handleEdit = useCallback((): void => {
 41→    router.push(`/recipe/${id}/edit`);
 42→  }, [router, id]);
 43→
 44→  const handleBack = useCallback((): void => {
 45→    router.back();
 46→  }, [router]);
 47→
 48→  const handleSwipe = useCallback(
 49→    (direction: SwipeDirection): void => {
 50→      if (direction === "right") {
 51→        router.back();
 52→      }
 53→    },
 54→    [router],
 55→  );
 56→
 57→  const handleDelete = useCallback((): void => {
 58→    Alert.alert(t("deleteRecipe.title"), t("deleteRecipe.message"), [
 59→      {
 60→        text: t("deleteRecipe.cancel"),
 61→        style: "cancel",
 62→      },
 63→      {
 64→        text: t("deleteRecipe.confirm"),
 65→        style: "destructive",
 66→        onPress: async () => {
 67→          await deleteRecipe(id);
 68→          router.replace("/");
 69→        },
 70→      },
 71→    ]);
 72→  }, [t, deleteRecipe, id, router]);
 73→
 74→  const [isZoomed, setIsZoomed] = useState(false);
 75→  const { width, height } = useWindowDimensions();
 76→  const insets = useSafeAreaInsets();
 77→  const { coverSize, onImageLoad } = useImageCoverSize(width, height);
 78→
 79→  const overlayStyle = useAnimatedStyle(() => ({
 80→    opacity: withTiming(isZoomed ? 0 : 1, { duration: 200 }),
 81→  }));
 82→
 83→  if (!recipe) {
 84→    return null;
 85→  }
 86→
 87→  const isProcessing =
 88→    recipe.status === "pending" || recipe.status === "processing";
 89→  const isReady = recipe.status === "ready";
 90→
 91→  return (
 92→    <View style={styles.container}>
 93→      <ZoomableImage
 94→        style={{ width, height }}
 95→        onZoomChange={setIsZoomed}
 96→        onSwipe={handleSwipe}
 97→      >
 98→        <View style={{ paddingTop: insets.top }}>
 99→          <ProgressiveImage
100→            uri={recipe.photoUri}
101→            thumbnailUri={recipe.thumbnailUri}
102→            style={coverSize ?? { width, height }}
103→            onLoad={onImageLoad}
104→          />
105→        </View>
106→      </ZoomableImage>
107→      <Animated.View
108→        style={[styles.overlay, overlayStyle]}
109→        pointerEvents={isZoomed ? "none" : "box-none"}
110→      >
111→        <MetadataOverlay
112→          metadata={recipe.metadata}
113→          isProcessing={isProcessing}
114→          onPress={handleEdit}
115→          disabled={!isReady}
116→        />
117→        <View pointerEvents="none" style={StyleSheet.absoluteFillObject}>
118→          {isProcessing && <ProcessingIndicator />}
119→          <DebugVisualization />
120→        </View>
121→        <BackButton onPress={handleBack} />
122→        <DeleteButton onPress={handleDelete} />
123→        <EditButton onPress={handleEdit} disabled={!isReady} />
124→      </Animated.View>
125→    </View>
126→  );
127→}
128→
129→const styles = StyleSheet.create({
130→  container: {
131→    flex: 1,
132→    backgroundColor: "#000000",
133→  },
134→  overlay: {
135→    ...StyleSheet.absoluteFillObject,
136→  },
137→});
